    public CardGameParticleProxy PlayParticle(PlayParticleInfo info)
    {
        if (!info.IsValid)
        {
            Debug.LogWarning("Playing invalid particle");
            return null;
        }

        CardGameParticleProxy result = new CardGameParticleProxy()
        {
            CreatedTime = Time.time,
            PlayInfo = info,
            Manager = this,
        };

        Debug.Log("Begin playing particle");

        AsyncOperationHandle<GameObject> handle = Addressables.LoadAssetAsync<GameObject>(info.ParticlePrefab);
        result.LoadHandle = handle;

        m_proxies.Add(result);

        if (handle.IsDone)
        {
            OnFinishedLoad(result);
        }
        else
        {
            handle.Completed += delegate (AsyncOperationHandle<GameObject> completeHandle)
            {
                OnFinishedLoad(result);
            };
        }

        return result;
    }

