    {
        if (proxy == null || proxy.IsStopping)
        {
            return;
        }

        if (!m_proxies.Contains(proxy))
        {
            return;
        }
        proxy._Internal_SetStopping();
        m_proxies.Remove(proxy);

        proxy._Internal_StopParticle();
    }

    private void OnFinishedLoad(CardGameParticleProxy proxy)
    {
        if (proxy == null)
        {
            return;
        }

        if (!m_proxies.Contains(proxy) || proxy.IsStopping || proxy.IsDestroyed)
        {
            return;
        }

