        if (proxy.LoadHandle.Result == null)
        {
            Debug.LogError($"Particle is null {proxy.PlayInfo.ParticlePrefab}");
            return;
        }

        GameObject instance = Instantiate(proxy.LoadHandle.Result, proxy.PlayInfo.StartPosition, proxy.PlayInfo.rotation, proxy.PlayInfo.Parent);
        CardGameParticle particleInstance = instance.GetComponent<CardGameParticle>();
        proxy.ParticleInstanceGO = instance;
